using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class EchoTool
{
    [McpServerTool, Description("Echoes the input message back to the caller.")]
    public static string Echo([Description("The message to echo")] string message)
    {
        return $"Echo: {message}";
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace McpHttpServer.Tools;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(Uri = "config://app/settings", Name = "App Settings",
        Description = "Returns the application configuration data.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = "Development",
            Features = new { EnableCaching = true, MaxConnections = 100 }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(Uri = "config://app/status", Name = "App Status",
        Description = "Returns the current application status.")]
    public static string GetAppStatus()
    {
        var status = new
        {
            Status = "Healthy",
            Uptime = Environment.TickCount64 / 1000,
            Timestamp = DateTime.UtcNow
        };

        return JsonSerializer.Serialize(status, new JsonSerializerOptions { WriteIndented = true });
    }
}

